#include <bits/stdc++.h>
using namespace std;
const int maxn=1e5+5,mod=1e9+7;
int nxt[maxn],match[maxn],dp[maxn];
void get_nxt(string s) {
	int n=s.size();
	s=' '+s;
	nxt[1]=0;
	int len=0;
	for(int i=2; i<=n; i++) {
		while(len>0&&s[i]!=s[len+1]) {
			len=nxt[len];
		}
		if(s[i]==s[len+1]) {
			len++;
		}
		nxt[i]=len;
	}
}
void kmp(string s,string t) {
	vector<int> cnt;
	int n=s.size(),m=t.size();
	s=' '+s;
	t=' '+t;
	int len=0;
	for(int i=1; i<=n; i++) {
		while(len==m||(len>0&&s[i]!=t[len+1])) {
			len=nxt[len];
		}
		if(s[i]==t[len+1]) {
			len++;
		}
		if(len==m) {
			match[i]=1;
		}
	}
}
void slove() {
	string a,b;
	cin>>a>>b;
	int la=a.size(),lb=b.size();
	for(int i=0; i<=la; i++) {
		match[i]=0;
		dp[i]=0;
	}
	get_nxt(b);
	kmp(a,b);
	dp[0]=1;
	for(int i=1; i<=la; i++) {
		dp[i]=dp[i-1];
		if(match[i]) {
			dp[i]=(dp[i]+dp[i-lb])%mod;
		} else
			dp[i]=max(dp[i],dp[i-1]);
	}
	cout<<dp[la]<<"\n";
}
int t;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>t;
	for(int i=1; i<=t; i++) {
		cout<<"Case #"<<i<<": ";
		slove();
	}
	return 0;
}
